himpl_hstar_hpure_r.solution:
Lemma himpl_hstar_hpure_r : forall (P:Prop) H H',
  P ->
  (H ==> H') ->
  H ==> H' \* \[P].
Proof using.
  introv HP M. intros h Hh.
  exists h Fmap.empty. splits.
  { apply M. auto. }
  { hnf. auto. }
  { auto. }
  { rewrite Fmap.union_empty_r. auto. }
Qed.

hexists_named_eq.solution:
Lemma hexists_named_eq : forall H,
  H = (\exists H', \[H' = H] \* H').
Proof using.
  intros. apply himpl_antisym.
  { intros h M. exists H. exists Fmap.empty h. splits.
    { hnf. auto. } { auto. } { auto. }
    { rewrite Fmap.union_empty_l. auto. } }
  { intros h (H'&h1&h2&(E1&HE)&M2&D&U). subst.
    rewrite Fmap.union_empty_l in U. subst. auto. }
Qed.
